const raw =
  $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text ??
  $input.first().json.text ??
  '';
let post;
try {
  post = JSON.parse(raw);
} catch {
  const match = raw.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('Gemini did not return JSON');
  post = JSON.parse(match[0]);
}
const imagePrompt = post.image_prompt || post.title || 'casino neon lights abstract';
const cover_image_url =
  'https://image.pollinations.ai/prompt/' +
  encodeURIComponent(imagePrompt + ', professional blog hero, wide 16:9, no text, no watermark') +
  '?width=1200&height=630&nologo=true';
return [{ json: { ...post, cover_image_url, status: 'draft' } }];
